//refAssemblies: TCAdmin.SDK.dll, TCAdmin.GameHosting.SDK.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll, TCAdmin.Web.Shared.dll, System.Text.Json.dll
using System;
using System.IO;
using System.Linq;
using System.Text.Json;
using TCAdmin.GameHosting.SDK.RconProviders;
using TCAdmin.SDK.Hubs.Models.GameQuery;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// CustomQueryProtocol for Squad. Squad dropped Steam A2S after its EOS migration, so query the
// server's own RCON (ShowServerInfo) for live player count / name / map. The RCON password + port
// come from SquadGame/ServerConfig/Rcon.cfg (Password + Port set to the allocated RCON port).
string address = Variables.Parse<string>("Address", ThisService.IPAddress);
int rconPort = ThisService.RconPort;
string password = "";

string rconCfg = Path.Combine(ThisService.RootDirectory, "SquadGame", "ServerConfig", "Rcon.cfg");
if (File.Exists(rconCfg))
{
    foreach (string raw in File.ReadAllLines(rconCfg))
    {
        string line = raw.Trim();
        if (line.StartsWith("//")) continue;
        if (line.StartsWith("Password=", StringComparison.OrdinalIgnoreCase))
            password = line.Substring("Password=".Length).Trim();
        else if (line.StartsWith("Port=", StringComparison.OrdinalIgnoreCase)
                 && int.TryParse(line.Substring("Port=".Length).Trim(), out int p))
            rconPort = p;
    }
}

if (string.IsNullOrEmpty(password))
{
    ScriptConsole.WriteLine("Squad query: RCON password is not set in Rcon.cfg - cannot query.");
    return; // no ReturnValue -> query monitoring reports offline
}

var factory = RconClientFactories.FirstOrDefault(f => f.Protocol == "source");
if (factory == null)
{
    ScriptConsole.WriteLine("Squad query: no 'source' RCON factory registered (monitor-only).");
    return;
}

string info;
await using (var rcon = factory.Create())
{
    await rcon.ConnectAsync(address, rconPort, password, ThisCancellationToken);
    info = await rcon.ExecuteCommandAsync("ShowServerInfo", ThisCancellationToken);
}

if (string.IsNullOrWhiteSpace(info))
{
    ScriptConsole.WriteLine("Squad query: empty ShowServerInfo response.");
    return;
}

using (var doc = JsonDocument.Parse(info))
{
    var root = doc.RootElement;

    string GetStr(string key, string dflt)
    {
        if (root.TryGetProperty(key, out var el))
            return el.ValueKind == JsonValueKind.String ? (el.GetString() ?? dflt) : el.ToString();
        return dflt;
    }
    int GetInt(string key, int dflt)
    {
        if (root.TryGetProperty(key, out var el))
        {
            if (el.ValueKind == JsonValueKind.Number && el.TryGetInt32(out int n)) return n;
            if (el.ValueKind == JsonValueKind.String && int.TryParse(el.GetString(), out int s)) return s;
        }
        return dflt;
    }

    Globals.ReturnValue = new GameQueryResponse
    {
        Status = "online",
        Hostname = $"{address}:{ThisService.GamePort}",
        Name = GetStr("ServerName_s", ThisService.Name),
        GameType = GetStr("GameMode_s", ""),
        Map = GetStr("MapName_s", ""),
        NumPlayers = GetInt("PlayerCount_I", 0),
        MaxPlayers = GetInt("MaxPlayers", ThisService.Slots)
    };
}
